INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, created_at, updated_at) VALUES (1, '阿根廷被指踢球脏，梅西遭质疑', 26.237, 126, 22, '2026-07-05 15:46:24', '2026-07-11 22:16:18', '2026-07-10 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.5, 0.28, 0.22, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '裁判之前取消了埃及的进球，理由是阿根廷的犯规，是在回看VAR后而在同一场比赛中，阿根廷球员对埃及球员犯规，进攻以阿根廷进球结束，裁判没有回看VAR他们是足球界的犹太复国主义者#阿根廷战埃及裁判称判罚非常公平##裁判 偏心#。（也可能是视角问题）埃及真的也是大心脏，这环境下一个二个好像还很乐观下半场，51分钟阿根廷一个任意球，摔倒有点轻易55分钟，梅西捂牙倒了，阿根廷一个任意球这场埃及门将，真的轻描淡写的达到顶级水平57分钟，埃及那一连串的运动过人，最后配合进球，太梦幻了神了，59分钟把这个球回溯到两分钟之前，判犯规没了，然后阿根廷获得下半场第三个任意球66分钟，埃及球员紧紧背着双手去断球，有点喜感66分钟后半，埃及进球，这个没有回溯点了69分钟，埃及一个轻易倒，有点青涩78分钟，阿根廷头球破门，回放没有越位83分钟，梅西破门VAR判断79分钟进球没有越位88分钟，阿根廷任意球，差点破门90分钟阿根廷断了埃及一个很有威胁的配合，比赛似乎进入正常状态91分钟，阿根廷进球，比分反超。一、阿根廷全队应得处罚（统一埃及严苛尺度）1. 直接红牌2张（暴力行为，IFAB规则无球击打面部=暴力行为直红）1. 莫利纳上半场无球抬手击打埃及阿舒尔面部，无球对抗下主动攻击头部，标准直红 2. 德保罗第12分钟亮鞋底全力蹬踏对手小腿，过度力量危及对手，严重犯规直红档，至少红牌2. 黄牌合计11张（竞技犯规+围堵抗议）竞技战术类黄牌（对标兹科拉拽即出牌）1. 麦卡利斯特3次无球拉扯球衣阻挡反击 → 3黄2. 罗梅罗多次背后推搡、卡位垫背干扰 → 2黄3. 全队其余隐蔽拉扯、脚下踮脚阻挡、冲撞干扰独立动作3次 → 3黄小计竞技黄牌：8张围堵、抗议裁判类黄牌（埃及聚集质问全部吃牌）梅西、恩佐、德保罗三次独立集体围堵裁判、大幅度手势施压，对应埃及4张抗议黄牌尺度 → 3黄小计抗议黄牌：3张阿根廷汇总红牌：2张黄牌：11张实际全场：0黄0红二、埃及全队应得处罚（完全套用本场裁判对待埃及自身的严苛标准，不放宽）无新增红牌动作：全场无蹬踏、击打、暴力伤人行为，无直红动作黄牌合计12张1. 本场实际已吃到5张：61''兹科战术拉拽1张。', '埃及、法国、上半场', '这场比赛是为了洗阿根廷的污水的，因为阿根廷也是非常脏的一个队，如果不找一个其它队来转移视线，大家就会。', '["萨拉", "恩佐", "弗朗索瓦", "西耶", "莫利纳"]', '{"credibility_score": 0.296, "official_ratio": 0.175, "verified_ratio": 0.381, "plain_user_ratio": 0.619, "verification_dist": {"普通用户": 0.619, "官方平台": 0.175, "认证个人": 0.167, "头部认证个人": 0.024, "认证机构": 0.016}, "factors": []}', '2026-07-13 00:05:18', '2026-07-13 00:05:18');
