INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, created_at, updated_at) VALUES (11, '六蓝水库最近的村怎么样了', 27.054, 91, 32, '2026-07-06 13:25:09', '2026-07-11 22:40:52', '2026-07-10 12:00:00', 'mid_high', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.34, 0.301, 0.359, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '个人初步推测为溢洪道受损后泄水不畅，导致库水位急速上涨，造成洪水漫坝，导致溃坝，分析如下：六篮水库总库容9000多万，为均质土坝，按照《水利水电工程等级及洪水标准》（SL252-2017）规定，工程规模属于中型水库（接近规模上限），对应的大坝建筑物级别为3级，土石坝对应洪水标准为100年设计，2000年校核。且按照坝顶高程计算方法，除水位外还考虑了安全超高、风浪雍高等因素，即便是极端天气，要达到2000年以上一遇洪水量级还是极小概率事件（具体情况需等待官方对洪水量级的确认），该坝建于1960年，处于3年困难时期，全国各地当时建设了不少中小型土石坝，用于灌溉、人饮供水，但当时处于摸着石头过河的年代，水库大坝普遍存在压实质量差、“三边”工程普遍、泄水能力不足等现象。具体到六蓝水库溃坝事件，据横州市融媒体中心报道，六蓝水库水利工程标准化建设完工才短短一年，“过去，这两座水库（六蓝水库与大陆水库）因设施老化、管理粗放，存在诸多安全隐患与功能短板。', '广西、横州、台风', '不是备战区，因为对越根本不需要准备，塔山英雄部队至今都还驻扎在贵港呢。', '["美莎克", "科普"]', '{"credibility_score": 0.589, "official_ratio": 0.484, "verified_ratio": 0.791, "plain_user_ratio": 0.209, "verification_dist": {"官方平台": 0.484, "普通用户": 0.209, "认证个人": 0.154, "头部认证个人": 0.11, "认证机构": 0.044}, "factors": ["well_sourced"]}', '2026-07-13 00:05:18', '2026-07-13 00:05:18');
