INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, created_at, updated_at) VALUES (25, '易烊千玺捐赠的挖掘机已到广西', 5.024, 12, 0, '2026-07-10 14:13:49', '2026-07-11 22:38:49', '2026-07-10 12:00:00', 'mid', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.667, 0.267, 0.067, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '驰援横州❤️心系广西 半亩花田捐赠100万元人民币 携手@中国乡村发展基金会 紧急向广西横州等受灾地区捐赠救灾物资 助力一线抢险救援与群众安置工作。爷爷不泡茶首批物资已送达 ·霸王茶姬紧急驰援广西防汛救灾 ·北京星巴克公益基金会捐款100万元 ·百胜中国携旗下多品牌捐赠300万元驰援灾区 ·驰援广西洪涝灾区，海底捞捐赠首批3万份自热火锅 农牧养殖 ·牧原公益基金会向广西受灾地区捐赠现金2000万元 食品饮料 ·卫龙美味向广西洪涝灾区捐赠100万元，助力防汛救灾与产业重建 ·蒙牛紧急驰援广西南宁洪涝灾区 ·伊利集团第一时间驰援广西南宁受灾群众 ·农夫山泉捐赠现金1000万元，调拨应急饮用水驰援广西 ·东鹏饮料捐款1000万元及10万瓶饮料驰援广西 互联网平台 ·腾讯公益慈善基金会启动2000万元备灾资金，驰援广西等地灾情 ·小米公益基金会捐赠1000万元现金，紧急驰援广西等地救灾 ·拼多多紧急捐赠1000万元，驰援广西防汛救灾 ·持续跟进。阿里巴巴驰援广西三批物资已经抵达 ·网易捐赠首批25000份物资支援救灾 ·20万份物资陆续送达，美团驰援广西受灾地区 ·京东物流捐赠生活急需物资，送往广西南宁洪涝灾区 汽车制造 ·比亚迪慈善基金会捐赠1000万元驰援广西灾区 纺织服饰 ·安踏集团携手中华慈善总会捐赠1000万元物资 紧急驰援广西救灾 ·李宁集团捐赠2000万元物资驰援救灾一线 ·特步集团紧急捐赠1000万元物资驰援广西、湖北、甘肃等受灾地区 ·361°集团携手中华慈善总会捐赠1000万元物资全力支援广西救灾 ·鸿星尔克携手中华社会救助基金会捐赠800万元物资驰援广西受灾地区 ·匹克集团携手中华慈善总会捐赠500万元物资全力驰援抗洪救灾一线 ·波司登紧急捐赠1000万元物资全力支援广西抗洪救灾一线 ·罗莱生活捐赠200万元物资驰援广西防汛救灾 潮玩文创 ·泡泡玛特捐赠1000万元人民币，驰援救灾一线 一、连锁餐饮 蜜雪冰城向广西受灾地区捐赠1000万元，支援防汛救灾和产业恢复 喜茶再次捐赠200万元驰援广西防汛救灾 7月7日，喜茶宣布驰援广西防汛救灾，灾情发生后，喜茶联合中国乡村发展基金会开展灾区救援及物资援助。', '广西、横州、中国', '易烊千玺捐赠的挖掘机已到广西。', '["陈楚生", "美莎克"]', '{"credibility_score": 0.662, "official_ratio": 0.167, "verified_ratio": 0.917, "plain_user_ratio": 0.083, "verification_dist": {"认证机构": 0.583, "官方平台": 0.167, "认证个人": 0.167, "普通用户": 0.083}, "factors": []}', '2026-07-13 00:05:18', '2026-07-13 00:05:18');
