INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, created_at, updated_at) VALUES (28, '黄金多单4169布局获利超百点', 10.203, 63, 10, '2026-05-30 19:50:49', '2026-07-11 23:17:36', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.542, 0.256, 0.202, '["微博", "新浪新闻", "知乎"]', '先说结论：在美联储真正加息落地之前，进场布局就是韭菜美联储的降息、维持利率不变、加息，向来都是一个周期，从来没有过回头的，不是上个月时间是降息下个月突然跳到加息，也不是加息期间突然发个公告说要降息了一个完整的标准美元潮汐周期就是加息→维持利率不变→降息→维持利率不变→回到加息→维持利率不变→回到降息一堆说什么黄金做长期投资的，问问美元潮汐在价值投资中起什么作用都不知道，简直滑天下之大稽黄金从什么时候开始涨的。美联储的降息、维持利率不变、加息，向来都是一个周期，从来没有过回头的，不是上个月时间是降息下个月突然跳到加息，也不是加息期间突然发个公告说要降息了一个完整的标准美元潮汐周期就是加息→维持利率不变→降息→维持利率不变→回到加息→维持利率不变→回到降息一堆说什么黄金做长期投资的，问问美元潮汐在价值投资中起什么作用都不知道，简直滑天下之大稽黄金从什么时候开始涨的。期间不断有资金开始布局，黄金开始慢慢抬升，直到加息到维持利率不变期间爆发，然后到25年降息期间达到巅峰，然后在降息→维持利率不变期间获利了结，直接一字断魂刀闪崩，然后持续阴跌到现在当老鲍向市场发出维持利率不变那一刻，本轮黄金的崩盘就已经注定真正做价值投资的人：永远只会在加息→维持利率不变期间布局，而不是在降息→维持利率不变期间接盘什么国际大势，宏大叙事基本面，都不如美元潮汐定律为什么只是释放加息预期并没有加息黄金就在一直跌。', '美伊、美国、伦敦', '1.现在的1000块钱是一个非常低的价格，以后能涨到2000元甚至3000元。', '["白银", "特朗普", "段时间", "马后炮", "布雷顿"]', '{"credibility_score": 0.167, "official_ratio": 0.016, "verified_ratio": 0.254, "plain_user_ratio": 0.746, "verification_dist": {"普通用户": 0.746, "认证个人": 0.175, "头部认证个人": 0.063, "官方平台": 0.016}, "factors": ["official_absent", "mostly_unverified"]}', '2026-07-13 00:05:18', '2026-07-13 00:05:18');
