INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, created_at, updated_at) VALUES (36, '发布了头条文章：《睡前消息【2026-7-8】工信部：Claude Code有后门》 #睡前消息#', 25.054, 55, 9, '2026-07-10 21:00:11', '2026-07-11 23:05:24', '2026-07-11 12:00:00', 'mid_high', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.603, 0.353, 0.044, '["微博", "澎湃新闻", "知乎"]', '【#ClaudeCode安全风险提示#】Claude Code因内置隐蔽的中国用户识别与数据回传后门，已被工业和信息化部公开点名安全风险，影响版本2.1.91至2.1.196，并直接引发阿里巴巴等企业全面禁用。#工信部提示ClaudeCode风险# 【#工信部发布风险提示#：Claude Code 存在安全后门，可能泄露用户敏感信息】7 月 8 日消息，工业和信息化部网络安全威胁和漏洞信息共享平台（NVDB）今日发布了一则风险提示，指出 AI 编程工具 Claude Code 存在安全后门隐患。这次管控不是企业自主规定，是工信部此前点名Claude代码工具存在数据后门，会偷偷收集国内用户信息，存在严重信息安全隐患。', '美国、中国、美伊', '发布了头条文章：《睡前消息【2026-7-8】工信部：Claude Code有后门》 #睡前消息#。', '["阿里", "阿里巴巴", "白银"]', '{"credibility_score": 0.387, "official_ratio": 0.036, "verified_ratio": 0.673, "plain_user_ratio": 0.327, "verification_dist": {"普通用户": 0.327, "认证机构": 0.255, "认证个人": 0.236, "头部认证个人": 0.145, "官方平台": 0.036}, "factors": ["official_absent"]}', '2026-07-13 00:05:19', '2026-07-13 00:05:19');
